#include <bits/stdc++.h>
using namespace std;

class Retea {
 public:
        void solve() {
            read_input();
            tarjan_cv();
            print_output();
        }

 private:
    // numarul maxim de noduri
    static constexpr int NMAX = (int)1e4 + 1;
    // n = numarul de noduri, m = numarul de muchii
    int n, m;
    // listele de adiacenta pentru graf
    vector<int> adj[NMAX];
    // vectorul de parinti din parcurgerea DFS
    vector<int> parent;
    // vectorul pentru timpii de descoperire din DFS
    vector<int> found;
    // vectorul pentru valorile low_link specifice algoritmului Tarjan
    vector<int> low_link;
    // vectorul rezultatelor (valorile obtinute prin eliminarea fiecarui nod)
    vector<int> result;
    // count_nodes[v] = numarul de noduri din subarborele DFS cu radacina v
    vector<int> count_nodes;
    // vector noduri vizitate folosit la DFS
    vector<bool> visited;
    // functie de citire a datelor de intrare
    void read_input() {
        ifstream fin("retea.in");
        fin >> n >> m;
        for (int i = 1, x, y; i <= m; i++) {
            fin >> x >> y;
            adj[x].push_back(y);
            adj[y].push_back(x);
        }
        fin.close();
    }
    // algoritmul lui tarjan pentru puncte de articulatie
    void tarjan_cv() {
        // initializare vectori
        parent = vector<int>(n + 1, -1);
        found = vector<int>(n + 1, -1);
        low_link = vector<int>(n + 1, -1);
        // initializarea lui result este astfel, deoarece dupa eliminarea
        // unui nod sigur se distrug conexiunile de la acest nod la celelalte
        // n - 1 noduri (bilateral)
        int aux = 2 * n - 2;
        result = vector<int>(n + 1, aux);
        // initializare vectori (continuare)
        count_nodes = vector<int>(n + 1, 1);
        visited = vector<bool>(n + 1);
        int timestamp = 0;
        // parcurgerea incepe din nodul 1
        dfs(1, timestamp);
    }
    // functie pentru DFS, auxiliara algoritmului lui Tarjan
    void dfs(int node, int& timestamp) {
        // descopera nod
        found[node] = ++timestamp;
        low_link[node] = found[node];
        // marcheaza ca vizitat
        visited[node] = true;
        // sum si sumSquares sunt explicate in README
        int sum = 0;
        int sumSquares = 0;
        // numarul de copii ai nodului node
        int children = 0;
        // pentru vecinii lui node
        for (auto neigh : adj[node]) {
            // daca nu a fost vizitat deja
            if (!visited[neigh]) {
                // incrementeaza numarul de copii
                children++;
                // marcheaza nodul ca parinte al vecinului
                parent[neigh] = node;
                // continua parcurgerea in adancime, prin vecin
                dfs(neigh, timestamp);
                // aduna numarul de noduri din subarborele DFS cu radacina
                // in nodul neigh la numarul de noduri din subarborele DFS cu
                // radacina in nodul node
                count_nodes[node] += count_nodes[neigh];
                // updateaza low_link node daca poate
                low_link[node] = min(low_link[node], low_link[neigh]);
                // daca nodul este punct de articulatie (nu e radacina)
                if (parent[node] != -1 && low_link[neigh] >= found[node]) {
                    // modifica sum si sumSquares (explicate in README)
                    sum += count_nodes[neigh];
                    sumSquares += count_nodes[neigh] * count_nodes[neigh];
                } else if (parent[node] == -1 && children > 1) {
                    // daca nodul este punct de articulatie (e radacina),
                    // modifica sum si sumSquares (explicate in README)
                    sum += count_nodes[neigh];
                    sumSquares += count_nodes[neigh] * count_nodes[neigh];
                }
            } else if (neigh != parent[node]) {
                // daca a fost vizitat si node nu este parintele sau,
                // incearca sa updateze low_link
                low_link[node] = min(low_link[node], found[neigh]);
            }
        }
        // ia in considerare si restul de noduri in sum si sumSquares
        sumSquares += (n - 1 - sum) * (n - 1 - sum);
        sum = n - 1;
        // calculeaza numarul de legaturi distruse prin eliminarea nodului
        // node
        result[node] += sum * sum - sumSquares;
    }
    // afiseaza rezultatul
    void print_output() {
        ofstream fout("retea.out");
        for (int i = 1; i <= n; i++) {
            fout << result[i] << "\n";
        }
        fout.close();
    }
};

int main() {
    auto* task = new (nothrow) Retea();
    if (!task) {
        cerr << "new failed: WTF are you doing? Throw your PC!\n";
        return -1;
    }
    task->solve();
    delete task;
    return 0;
}

import java.io.BufferedReader;
import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.StringTokenizer;

@SuppressWarnings("unchecked")
public class Retea {
	static class MyScanner {
		BufferedReader br;
		StringTokenizer st;

		public MyScanner() {
			br = new BufferedReader(new InputStreamReader(System.in));
		}
		public MyScanner(String f) throws FileNotFoundException {
			br = new BufferedReader(new FileReader(f));
		}

		String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		int nextInt() {
			return Integer.parseInt(next());
		}

		long nextLong() {
			return Long.parseLong(next());
		}

		double nextDouble() {
			return Double.parseDouble(next());
		}

		String nextLine() {
			String str = "";
			try {
				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}

		void close() {
			try {
				if (br != null) {
					br.close();
				}
			} catch (IOException ex) {
				ex.printStackTrace();
			}
		}
	}

	static class Task {
		int V, E;
		int time;
		int[] color, discover, parent, low, art, nodesCount, depth;
		ArrayList<Integer>[] edges;
		ArrayList<Integer>[] componentSum;

		public void solve() {
			getResult();
		}

		void explore(int node) {
			discover[node] = low[node] = time++;
			color[node] = 1;
			nodesCount[node] = 1;
			for (Integer successor:edges[node]) {
				if (color[successor] == 0) {
					depth[successor] = depth[node] + 1;
					parent[successor] = node;

					explore(successor);

					nodesCount[node] += nodesCount[successor];
					low[node] = Math.min(low[node],
							low[successor]);
					if (parent[node] != -1 && low[successor] >= discover[node]) {
						if (componentSum[node] == null) {
							componentSum[node] = new ArrayList<>();
						}
						art[node] = 1;
						componentSum[node].add(nodesCount[successor]);
					}
					if (node == 0) {
						componentSum[0].add(nodesCount[successor]);
					}
				} else {
					if (parent[node] != successor) {
						low[node] = Math.min(low[node], discover[successor]);
					}
				}
			}
		}

		private void getResult() {
			try {
				Retea.MyScanner sc = new Retea.MyScanner("retea.in");
				PrintWriter pw = new PrintWriter(new File("retea.out"));

				V = sc.nextInt();
				E = sc.nextInt();
				int from, to;

				time = 0;
				color = new int[V];
				discover = new int[V];
				parent = new int[V];
				low = new int[V];
				art = new int[V];
				nodesCount = new int[V];
				depth = new int[V];

				edges = new ArrayList[V];
				componentSum = new ArrayList[V];
				for (int i = 0; i < V; i++) {
					parent[i] = -1;
					edges[i] = new ArrayList<>();
				}

				//Read graph structure
				for (int i = 0; i < E; i++) {
					from = sc.nextInt() - 1;
					to = sc.nextInt() - 1;
					edges[from].add(to);
					edges[to].add(from);
				}
				//Knowing the graph is Conex we can start the discovery
				//From node 0;
				componentSum[0] = new ArrayList<>();
				explore(0);
				int totalSum;
				int lostConnections;
				if (componentSum[0].size() > 1) {
					art[0] = 1;
					lostConnections = 2 * V - 2;
					for (int in:componentSum[0]) {
						lostConnections += in * (V - 1 - in);
					}
					pw.println(lostConnections);
				} else {
					pw.println(2 * V - 2);
				}
				sc.close();
				for (int i = 1; i < art.length; i++) {
					if (art[i] == 0) {
						pw.println(2 * V - 2);
					} else {
						totalSum = 0;
						lostConnections = 2 * V - 2;
						for (Integer in:componentSum[i]) {
							totalSum += in;
							lostConnections += in * (V - 1 - in);
						}
						//compute the remaining sum
						lostConnections += totalSum * (V - 1 - totalSum);
						pw.println(lostConnections);
					}
				}
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}
	}

	public static void main(String[] args) {
		new Task().solve();
	}
}
